function(g, rect, comp, data, view) {var blur = comp.getValue('blur');
if (blur <= 0) return;

var realView = view;
var getView = comp.getValue('getViewFunc');

var saturate = comp.getValue('saturate');
var brightness = comp.getValue('brightness');
var invert = comp.getValue('invert');

if (ht.Default.isFunction(getView)) {
    realView = getView(data, view);
}
if (!realView || !realView.getCanvas) return;

var x = rect.x;
var y = rect.y;
var width = rect.width;
var height = rect.height
var radius = comp.getValue('radius');

g.save();

g.beginPath();
g.moveTo(x + radius, y);
g.lineTo(x + width - radius, y);
g.arcTo(x + width, y, x + width, y + radius, radius);
g.lineTo(x + width, y + height - radius);
g.arcTo(x + width, y + height, x + width - radius, y + height, radius);
g.lineTo(x + radius, y + height);
g.arcTo(x, y + height, x, y + height - radius, radius);
g.lineTo(x, y + height);
g.arcTo(x, y, x + radius, y, radius);
g.clip();

g.filter = 'blur(' + blur + 'px) saturate('+ saturate +') ' + 'brightness(' + brightness + ') ' +  'invert(' + invert +')';

var drawBackgroundFunc = comp.getValue('drawBackgroundFunc');
drawBackgroundFunc(g, rect, comp, blur, realView);

var getColorFunc = comp.getValue('getColorFunc');
var color = getColorFunc(comp, data, view);
if (color) {
    g.fillStyle = color;
    g.fill();
}

g.restore();}

getColorFunc.defaultValue:
function(comp, data, view) {var color = comp.getValue('color');
if (!ht.Default.isString(color)) return;

var opacity = comp.getValue('alpha');
if (opacity === 0) return;

var r, g, b;
// #000 / #000000
var res = color.match(/#([0-9a-fA-F]{6}|[0-9a-fA-F]{3})/i);
if (res) res = res[1];
if (res) {
    if (res.length === 3) {
        r = parseInt(res[0], 16);
        g = parseInt(res[1], 16);
        b = parseInt(res[2], 16);
    }
    else {
        r = parseInt(res.slice(0, 2), 16);
        g = parseInt(res.slice(2, 4), 16);
        b = parseInt(res.slice(4), 16);
    }
    return 'rgba(' + ([r, g, b, opacity].join(', ')) + ')'
}

// rgb(0, 0, 0) / rgba(0, 0, 0, 1)
res = color.match(/rgba?\((.*)\)/i);
if (res) res = res[1];
if (res) {
    res = res.split(',');
    res[3] = opacity;
    return 'rgba(' + res.join(', ') + ')';
}

// 其他
res = ht.Default.toColorData(color);
res[3] = opacity;
return 'rgba(' + res.join(', ') + ')';}

drawBackgroundFunc.defaultValue:
function(g, rect, comp, blur, view) {var filterCanvas = comp.__filterCanvas__;
if (!filterCanvas) {
    filterCanvas = comp.__filterCanvas__ = document.createElement('canvas');
    filterCanvas.dynamic = true;
}

var x = rect.x - blur, y = rect.y - blur;
var w = rect.width + 2 * blur;
var h = rect.height + 2 * blur;

filterCanvas.width = w;
filterCanvas.height = h;

var filterCtx = filterCanvas.getContext('2d');
filterCtx.clearRect(0, 0, w, h);

var t = g.getTransform();
t = new ht.Math.Matrix2d().set(t.a, t.b, t.c, t.d, t.e, t.f);
var p0 = t.apply({ x: x, y: y });
var p1 = t.apply({ x: x + w, y: y + h });
filterCtx.drawImage(view.getCanvas(), p0.x, p0.y, p1.x - p0.x, p1.y - p0.y, 0, 0, w, h);

// 往外扩充 blur 像素，为了让整体 blur 效果更均衡，因为 blur 的边缘会比较透
g.drawImage(filterCanvas, x, y, w, h);}
